import{c as e,Q as o,j as a,m as r}from"./chunks/framework.hhGiamYR.js";const c=JSON.parse('{"title":"致走在高处的朋友——一个被命运摔落的人，关于友谊的实话","description":"","frontmatter":{"title":"致走在高处的朋友——一个被命运摔落的人，关于友谊的实话","date":"2026-05-27T00:00:00.000Z","source":"co-created","seed":"如果你有一个好朋友，但由于命运和境遇的不同，他逐渐走上了高于你的道路","style":"let","tags":["友谊","韦托里","书信","命运"],"skill_used":"Machiavelli Digital Twin"},"headers":[],"relativePath":"seeds/unequal-friends/index.md","filePath":"seeds/unequal-friends/index.md"}'),l={name:"seeds/unequal-friends/index.md"};function p(u,t,i,n,s,q){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="致走在高处的朋友——一个被命运摔落的人-关于友谊的实话" tabindex="-1">致走在高处的朋友——一个被命运摔落的人，关于友谊的实话 <a class="header-anchor" href="#致走在高处的朋友——一个被命运摔落的人-关于友谊的实话" aria-label="Permalink to &quot;致走在高处的朋友——一个被命运摔落的人，关于友谊的实话&quot;">​</a></h1><blockquote><p>来自佛罗伦萨乡下的一封信。</p><p>你问我：如果好朋友因为命运走到了比你高得多的位置，怎么相处？真正的朋友可以是地位悬殊的吗？</p><p>这个问题我活了三十年。我有一个叫弗朗切斯科·韦托里的朋友。1512年美第奇家族回到佛罗伦萨时，他被任命为驻罗马教廷大使——一人之下万人之上。我呢？同一天被罢免、下狱、被吊了六次。我们之间隔着的不是友谊的裂痕，是一整个命运的深渊。</p></blockquote><h2 id="最开始-我以为这只是一个-能帮我吗-的问题" tabindex="-1">最开始，我以为这只是一个&quot;能帮我吗&quot;的问题 <a class="header-anchor" href="#最开始-我以为这只是一个-能帮我吗-的问题" aria-label="Permalink to &quot;最开始，我以为这只是一个&quot;能帮我吗&quot;的问题&quot;">​</a></h2><p>我刚出狱时给韦托里写了第一封信，在信里我用了最本能的方式——请他帮忙。他是大使，我是阶下囚。他认识教廷里的人，我一个都不认识。</p><blockquote><p>📖 <strong>原文</strong>：致弗朗切斯科·韦托里，1513年3月</p><p>&quot;阁下：您想必已从保罗·韦托里处得知，在本城共同欢庆之际，我出狱了。我遭逢厄难的漫长故事，就不和您说了，我只想说，命运女神干尽了一切让我遭难的事情。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>然后我紧接着写道：</p><blockquote><p>&quot;您知道我们的朋友托托先生的处境。我恳求您和保罗对他施以援手。他和我只图一件事：让他当上教皇的仆人。&quot;</p></blockquote><p>现在回头看这封信，我有一个想抽自己耳光的地方：我请求他帮的是托托，不是我。我开不了口。就算在最低谷的时候，我也没有直接说出&quot;帮我找个差事&quot;——我说的永远是&quot;帮帮我们的朋友&quot;。这就是地位悬殊后的第一种反应：<strong>你开始把他当成一个资源，而不是一个人。</strong> 你开始精心措辞，你开始计算怎么说才不会让他觉得你在低三下四。而这些计算——不管他怎么回应——已经在毒害友谊了。</p><h2 id="后来-韦托里给了我一句让我永生难忘的话" tabindex="-1">后来，韦托里给了我一句让我永生难忘的话 <a class="header-anchor" href="#后来-韦托里给了我一句让我永生难忘的话" aria-label="Permalink to &quot;后来，韦托里给了我一句让我永生难忘的话&quot;">​</a></h2><p>他帮我了。或者说，他试了。但美第奇家族不给机会。最后他写信给我，说：</p><blockquote><p>📖 <strong>原文</strong>：弗朗切斯科·韦托里致马基雅维利，书信207</p><p>&quot;抱歉我什么都给不了您。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>这句话我读了很多遍。起初我觉得他在敷衍——你一个驻教廷大使，什么都给不了我？后来我才明白，他是真的给了不了。不是不够朋友。是他的手也被人绑着。他在那个位置上，也有他的迫不得已。</p><p>然后最奇怪的事发生了。在他承认他帮不了我之后，我们的友谊反而恢复了。我们开始写真正的信——不是请求和拒绝，是讨论政治、分析局势、分享每天在乡下掐死一只鸡的荒唐事。我给他讲我和屠夫在酒馆打牌的故事，他给我讲罗马主教们的阴谋。两个老朋友在各自的世界里，用信纸当绳子，拴住一段几乎被命运冲散的友谊。</p><p>这段友谊能活下来，不是因为我放弃了求助，也不是因为他克服了尴尬。而是因为我们找到了一个<strong>共同的战场</strong>——书信中的政治分析和互相调侃。在这件事上，我和他的地位是平等的。他是大使，我是农民——但分析起来势来，我们彼此需要对方的才智。</p><h2 id="所以回答你的问题" tabindex="-1">所以回答你的问题 <a class="header-anchor" href="#所以回答你的问题" aria-label="Permalink to &quot;所以回答你的问题&quot;">​</a></h2><p><strong>地位悬殊的朋友可以继续是朋友——前提是你们找到一个新的、与地位无关的共同基础。</strong></p><p>如果你们原本的友谊是建立在大学校园里一起吃饭、一起翘课、一起做傻事的那些回忆上——那这段友谊会随着地位的改变慢慢死去。因为那些东西再也回不来了。他没有时间和你一起吃饭了。他身边有一群新的人。你们共同的过去变得越来越远。</p><p>但如果你们能找到一件事——一件让地位变成无关紧要的事——那友谊就可以活。</p><p>对我和韦托里来说，那件事是&quot;分析政治局势&quot;。 对你们来说，可能是一起讨论文学、一起研究股票、一起分析体育比赛——什么都可以，只要是<strong>他能从中得到他从别处得不到的东西、你也能从中得到承认的事情</strong>。</p><p>这不是功利。这是让友谊从&quot;回忆过去&quot;变成&quot;创造新东西&quot;。</p><p>让我说得更直接一点：<strong>不要试图让他回到你的世界里。想办法进入一个你们俩都平等的新世界。</strong> 如果他读到一本好书，去读它，然后用你最好的见解回复他。如果他在某个问题上有专业领域，去了解那个领域。不要问&quot;你能帮我什么&quot;，要问&quot;我们在什么事情上还能互相需要&quot;。</p><p>这种感觉和跟一位地位比你高的朋友吃饭完全不同。食堂里你战战兢兢，不知道什么该说什么不该说。你们一起谈论政治或者书的时候——那些地位都不见了，只剩下两个在思考的人。</p><blockquote><p>📖 <strong>原文</strong>：韦托里致马基雅维利，1513年11月</p><p>&quot;我今天拜访了圣上，他告诉我……这封信写得潦草，敬请见谅。如果我看到任何新鲜事，我会用更好的笔迹给你写信。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>韦托里在罗马的教廷里掌握着机密。但他还是会用潦草的字迹给我写信——因为在&quot;分析局势&quot;这件事上，我是他的对等对话者。教廷里没人能像我一样预判翻出的牌面。大使的身份让我停下了请求，但没有停下思考。</p><h2 id="最后-能接受-他帮不了你" tabindex="-1">最后：能接受&quot;他帮不了你&quot; <a class="header-anchor" href="#最后-能接受-他帮不了你" aria-label="Permalink to &quot;最后：能接受&quot;他帮不了你&quot;&quot;">​</a></h2><p>这是最苦的药。韦托里真的帮不了我。不是不够朋友。是他身处的政治结构不允许。如果你的朋友走到高处后帮不了你——不是他的错，也不是你的错。是结构。看清这一点，你就不会在每次见面时无声地怨恨他。</p><p>&quot;抱歉我什么都给不了您。&quot;这句话在我们之间被说了很多次。但每一次说完之后，下一封信的开头仍然是&quot;亲爱的尼科洛&quot;和&quot;亲爱的弗朗切斯科&quot;。这段友谊没有给出我们最初想要的——一份差事、一次重新爬上去的机会。它给出了一个我们都没预料到的东西：一个证明——地位可以毁掉求助，但毁不掉真正的对话。</p><hr><p><em>原文可于 <a href="https://niflhum.top/machiavelli-library/" target="_blank" rel="noreferrer">machiavelli-library</a> 查证</em></p>',29)])])}const d=e(l,[["render",p]]);export{c as __pageData,d as default};
